mapper.select:
SELECT database_id as databaseId, session_phase as sessionPhase, session_progress as sessionProgress, autovacuum, elapsed_seconds as elapsedSeconds, heap_blks_total as heapBlksTotal, heap_blks_scanned as heapBlksScanned, heap_blks_vacuumed as heapBlksVacuumed, COALESCE(n_dead_tup, 0) as deadTupleTotal FROM vacuum_raw_metrics WHERE session_phase IS NOT NULL AND session_phase != 'completed'
AND database_id = #{databaseId}
ORDER BY created_at DESC LIMIT 10

SELECT COALESCE(max_workers, 0) as max_workers FROM vacuum_raw_metrics WHERE max_workers IS NOT NULL
AND database_id = #{databaseId}
ORDER BY created_at DESC LIMIT 1

SELECT COALESCE(active_workers, 0) as active_workers FROM vacuum_raw_metrics WHERE active_workers IS NOT NULL
AND database_id = #{databaseId}
ORDER BY created_at DESC LIMIT 1
